package com.aadil.jobtracker.UserService;import com.aadil.jobtracker.UserRepository.UserRepository;import com.aadil.jobtracker.entity.UserEntity;import org.jspecify.annotations.NonNull;import org.springframework.security.core.userdetails.UserDetails;import org.springframework.security.core.userdetails.UserDetailsService;import org.springframework.security.core.userdetails.UsernameNotFoundException;import org.springframework.stereotype.Service;@Servicepublic class UserServiceDetailsImp implements UserDetailsService {    private final UserRepository userRepository;    public UserServiceDetailsImp(UserRepository userRepository) {        this.userRepository = userRepository;    }    @Override    public @NonNull UserDetails loadUserByUsername(@NonNull String name) {        UserEntity user=userRepository.findByName(name).orElseThrow(()->new UsernameNotFoundException("Username NOT found"));        return org.springframework.security.core.userdetails.User.withUsername(user.getName()).password(user.getPassword()).roles(user.getRoles()).build();    }}